/**
 * Page Builder Toolbar - Top Action Bar
 * Purpose: Main actions like save, preview, publish
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import React from 'react';

interface ToolbarProps {
  onSave: () => Promise<void>;
  isSaving: boolean;
  isPreviewMode: boolean;
  onTogglePreview: () => void;
  previewMode: 'desktop' | 'tablet' | 'mobile';
  onPreviewModeChange: (mode: 'desktop' | 'tablet' | 'mobile') => void;
  pageId?: string;
  pageStatus?: string;
  onPublish?: () => Promise<void>;
}

export function Toolbar({
  onSave,
  isSaving,
  isPreviewMode,
  onTogglePreview,
  previewMode,
  onPreviewModeChange,
  pageId,
  pageStatus,
  onPublish,
}: ToolbarProps) {
  const [isPublishing, setIsPublishing] = React.useState(false);

  const handlePublish = async () => {
    if (!pageId) return;
    
    setIsPublishing(true);
    try {
      const token = localStorage.getItem('adminToken');
      const res = await fetch(`/api/admin/pages/${pageId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify({ status: 'published' })
      });

      const result = await res.json();
      console.log('Publish result:', result);

      if (res.ok && result.success) {
        if (onPublish) await onPublish();
        alert('Page published successfully!');
        window.location.reload();
      } else {
        alert('Failed to publish: ' + (result.error || 'Unknown error'));
      }
    } catch (err) {
      console.error('Publish error:', err);
      alert('Failed to publish page');
    } finally {
      setIsPublishing(false);
    }
  };
  return (
    <div className="h-16 bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between px-6">
      {/* Left Section - Page Info */}
      <div className="flex items-center space-x-4">
        <h1 className="text-lg font-semibold text-gray-900 dark:text-white">
          Page Builder
        </h1>
        <div className="text-sm text-gray-500 dark:text-gray-400">
          Visual Editor
        </div>
      </div>

      {/* Center Section - Device Preview */}
      {!isPreviewMode && (
        <div className="flex items-center space-x-1 bg-gray-100 dark:bg-gray-700 rounded-lg p-1">
          {[
            { mode: 'desktop' as const, icon: '🖥️', label: 'Desktop' },
            { mode: 'tablet' as const, icon: '📱', label: 'Tablet' },
            { mode: 'mobile' as const, icon: '📱', label: 'Mobile' },
          ].map(({ mode, icon, label }) => (
            <button
              key={mode}
              onClick={() => onPreviewModeChange(mode)}
              className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                previewMode === mode
                  ? 'bg-white dark:bg-gray-600 text-gray-900 dark:text-white shadow-sm'
                  : 'text-gray-600 dark:text-gray-300 hover:text-gray-900 dark:hover:text-white'
              }`}
              title={label}
            >
              <span className="mr-2">{icon}</span>
              <span className="hidden sm:inline">{label}</span>
            </button>
          ))}
        </div>
      )}

      {/* Right Section - Actions */}
      <div className="flex items-center space-x-3">
        {/* Preview Toggle */}
        <button
          onClick={onTogglePreview}
          className={`px-4 py-2 rounded-lg font-medium transition-colors ${
            isPreviewMode
              ? 'bg-blue-600 text-white hover:bg-blue-700'
              : 'bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600'
          }`}
        >
          {isPreviewMode ? (
            <>
              <span className="mr-2">✏️</span>
              Edit
            </>
          ) : (
            <>
              <span className="mr-2">👁️</span>
              Preview
            </>
          )}
        </button>

        {/* Save Button */}
        <button
          onClick={onSave}
          disabled={isSaving}
          className="px-4 py-2 bg-green-600 hover:bg-green-700 disabled:bg-green-400 text-white rounded-lg font-medium transition-colors flex items-center"
        >
          {isSaving ? (
            <>
              <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent mr-2" />
              Saving...
            </>
          ) : (
            <>
              <span className="mr-2">💾</span>
              Save
            </>
          )}
        </button>

        {/* Publish Button */}
        <button
          onClick={handlePublish}
          disabled={isPublishing || pageStatus === 'published'}
          className="px-4 py-2 bg-violet-600 hover:bg-violet-700 disabled:bg-gray-400 text-white rounded-lg font-medium transition-colors flex items-center"
        >
          {isPublishing ? (
            <>
              <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent mr-2" />
              Publishing...
            </>
          ) : pageStatus === 'published' ? (
            <>
              <span className="mr-2">✅</span>
              Published
            </>
          ) : (
            <>
              <span className="mr-2">🚀</span>
              Publish
            </>
          )}
        </button>
      </div>
    </div>
  );
}